    // Start from numbers with popcount 1 (since the depth starts at 1)
    // and apply the popcount operation until we reach 1
    // We will use a set to keep track of visited numbers to avoid cycles
    const visited = new Set();
    const queue = [];

    // Initialize the queue with numbers that have exactly 1 bit set
    for (let i = 1; i <= n; i <<= 1) {
        if (i > n) break;
        queue.push(i);
    }

    let count = 0;

